import java.util.*; import java.util.stream.*;
public class TopScoringStudents { static class Student { String name; int marks; Student(String name, int marks) { this.name = name; this.marks = marks; } public String toString() { return name + " " + marks; } } public static void main(String[] args) { List<Student> students = Arrays.asList(new Student("Asha", 88), new Student("Bala", 95), new Student("Charu", 91), new Student("Deepak", 76)); List<Student> top = students.stream().sorted(Comparator.comparingInt((Student s) -> s.marks).reversed()).limit(3).collect(Collectors.toList()); System.out.println(top); } }
